"use client";

import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { onAuthStateChanged } from "firebase/auth";
import { API_URL } from "@/lib/api";
import { clearAuthSession, getUser, setAuthSession } from "@/lib/auth";
import { firebaseAuth } from "@/lib/firebase";
import type { User } from "@/lib/types";

export function AuthGate({ children }: { children: React.ReactNode }) {
  const router = useRouter();
  const [ready, setReady] = useState(false);

  useEffect(() => {
    return onAuthStateChanged(firebaseAuth, async (firebaseUser) => {
      if (!firebaseUser) {
        clearAuthSession();
        router.replace("/login");
        return;
      }

      try {
        const token = await firebaseUser.getIdToken();
        const cachedUser = getUser();

        if (cachedUser) {
          setAuthSession(token, cachedUser);
          setReady(true);
          return;
        }

        const response = await fetch(`${API_URL}/api/auth/me`, {
          headers: { Authorization: `Bearer ${token}` },
          cache: "no-store"
        });

        if (!response.ok) {
          throw new Error("Unable to load user profile.");
        }

        const data = (await response.json()) as { user: User };
        setAuthSession(token, data.user);
        setReady(true);
      } catch {
        clearAuthSession();
        router.replace("/login");
      }
    });
  }, [router]);

  if (!ready) {
    return <div className="flex min-h-screen items-center justify-center text-sm text-muted-foreground">Loading session...</div>;
  }

  return <>{children}</>;
}
